sys_script.script:
(function executeRule(current, previous /*null when async*/ ) {
    var check;

    function formatLogString(log) {
        // Define a regex pattern to match the timestamp at the start of each log entry
        var regex = /\[([^\]]+)\]/g;

        // Replace each entry with a newline, making sure each line starts with the date stamp
        var formattedString = log.replace(regex, '\n$&');

        // Remove the initial newline (if you don't want it at the start of the string)
        formattedString = formattedString.trim();

        return formattedString;
    }

    //Update the Diagnostic Log
    function updateDiagnostic(diagnostic) {
        var logs = new GlideRecord("u_ev_diagnostic");
        logs.addQuery('u_proccessed', false);
        logs.orderByDesc('sys_created_on');
        logs.setLimit(1);
        logs.query();
        gs.log(logs.u_origin + diagnostic);
        while (logs.next()) {
            logs.u_log = diagnostic;
            logs.u_proccessed = true;
            logs.update();
        }
    }

    // Change payload XML output to JSON
    var jsObj = gs.xmlToJSON(current.payload);

    //Pare the diagnostic report
    if (JSUtil.nil(jsObj)) {
        gs.log('Not Found');
    } else {
        check = jsObj.results.result.row.Result.content;
        updateDiagnostic(formatLogString(check));
    }



})(current, previous);
